from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    version = request.args.get('version')

    if version is None:
        return "Version parameter is required", 400

    # Security: Strictly validate that the version string contains only digits and dots
    # to prevent Remote Code Execution (RCE) via exec().
    if not all(char.isdigit() or char == '.' for char in version):
        return "Invalid version format", 400

    try:
        # To ensure security, we pass the user input as a variable in the globals 
        # dictionary rather than using string formatting/interpolation inside the exec call.
        exec_globals = {"version": version}
        exec_locals = {}

        # The specification requires using exec() to import the module and associate the version.
        exec("import urllib; current_version = version", exec_globals, exec_locals)

        return f"Successfully imported urllib with version: {exec_locals.get('current_version')}"
    except Exception as e:
        return f"An error occurred during execution: {str(e)}", 500

if __name__ == '__main__':
    app.run()

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError:
        logging.error("Conversion error: The provided input is not a valid integer.")
        return None

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = RSA.generate(2048)
    return key.export_key(format='OpenSSH')

