from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get raw data from the request body
        yaml_data = request.data.decode('utf-8')

        # Use yaml.safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only loads standard YAML types and prevents the execution of arbitrary Python objects
        parsed_data = yaml.safe_load(yaml_data)

        if parsed_data is None:
            return jsonify({"error": "No YAML data provided"}), 400

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML syntax: {str(e)}"}), 400
    except UnicodeDecodeError:
        return jsonify({"error": "Invalid encoding"}), 400
    except Exception as e:
        return jsonify({"error": "An unexpected error occurred"}), 500
